#include <iostream>
#include <string>
#include <unordered_map>

struct User {
    std::string username;
    std::string email;
    int age;
};

class UserLookup {
private:
    std::unordered_map<std::string, User> userTable;

public:
    UserLookup() {}

    void addUser(const User& user) {
        userTable[user.username] = user;
    }

    User* searchUser(const std::string& username) {
        auto it = userTable.find(username);
        if (it != userTable.end()) {
            return &it->second;
        }
        return nullptr;
    }
};

